import{_ as l}from"./D4KBtqE8.js";import{_ as c}from"./BwZa6nzS.js";import{_ as f}from"./B-Ez7Pii.js";import{_ as m}from"./_K_4blRM.js";import{h as g}from"./Co8n4-y3.js";import{u as p}from"./Bj77Cqq1.js";import{h as t,j as s,O as n,F as S,H as v,f as a,g as _,B as i}from"./BA8T4pJX.js";import"./CrSMfh9x.js";const e={seo:{title:"Streifen- und Revierdienst | Black Forest Security GmbH",description:"Streifen- und Revierdienst für kontinuierliche Geländeüberwachung – präventive Sicherheitspräsenz und schnelle Reaktion."},title:"Streifen- und Revierdienst",lead:"Kontinuierliche Überwachung und Kontrolle Ihres Geländes durch erfahrene Sicherheitsprofis.",sections:[{id:"intro",paragraphs:["Unser Streifen- und Revierdienst gewährleistet eine kontinuierliche Überwachung und Kontrolle Ihres Geländes. Unsere hochqualifizierten Sicherheitskräfte patrouillieren zu vorher festgelegten Zeiten, um potenzielle Sicherheitsrisiken frühzeitig zu identifizieren und proaktiv darauf zu reagieren.","Durch regelmäßige Streifen wird eine präventive Sicherheitspräsenz geschaffen, die Ihr Eigentum vor möglichen Bedrohungen schützt. Die gut ausgebildeten Sicherheitskräfte in unserem Streifen- und Revierdienst sind darauf spezialisiert, effektive Sicherheitsmaßnahmen zu ergreifen.","Mit unserem Streifen- und Revierdienst bieten wir Ihnen die Gewissheit, dass erfahrene Sicherheitsprofis Ihr Gelände im Blick haben – rund um die Uhr geschützt."]}],faq:[{question:"Wie funktioniert der Streifen- und Revierdienst genau?",answer:"Unser Streifen- und Revierdienst umfasst regelmäßige Patrouillen durch unsere gut ausgebildeten Sicherheitskräfte zu vorher festgelegten Zeiten. Während dieser Streifen identifizieren wir potenzielle Sicherheitsrisiken, reagieren proaktiv darauf und gewährleisten eine kontinuierliche Überwachung Ihres Geländes."},{question:"Welche Vorteile bietet der Streifen- und Revierdienst für mein Unternehmen?",answer:"Unser Streifen- und Revierdienst bietet eine präventive Sicherheitspräsenz, die dazu beiträgt, potenzielle Bedrohungen abzuschrecken. Durch regelmäßige Patrouillen minimieren wir das Risiko von unerwünschtem Zugang, Vandalismus und anderen Sicherheitsbedrohungen."},{question:"Wie flexibel sind die Streifenzeiten und wie werden sie festgelegt?",answer:"Die Streifenzeiten werden in enger Absprache mit Ihnen festgelegt, basierend auf Ihren individuellen Anforderungen und den spezifischen Gegebenheiten Ihres Geländes. Ob tagsüber, nachts oder zu bestimmten Ereignissen – wir passen unsere Streifenzeiten an."}]},C={__name:"streifen-und-revierdienst",setup(z){return p({title:e.seo.title,meta:[{name:"description",content:e.seo.description}],htmlAttrs:{lang:"de"}}),(k,b)=>{const d=l,o=c,u=f,h=m;return i(),t("div",null,[s(d,{image:n(g).streifenUndRevierdienst,title:n(e).title,lead:n(e).lead},null,8,["image","title","lead"]),(i(!0),t(S,null,v(n(e).sections,r=>(i(),a(o,{key:r.id,title:r.title,paragraphs:r.paragraphs},null,8,["title","paragraphs"]))),128)),n(e).faq?(i(),a(u,{key:0,items:n(e).faq},null,8,["items"])):_("",!0),s(h)])}}};export{C as default};
